    /// Bypass `eth_estimateUserOperationGas` with explicit limits.
    /// Useful when the bundler's simulator mis-estimates (notably
    /// alto in dev). `None` => let the bundler estimate.
    /// </summary>
    GasOverrides? @gasOverrides
) {
}

